#include<bits/stdc++.h>
using namespace std;
char c[1000010];
vector<long long> mp[1000010];
long long n,cnt,lst[1000010],sum[1000010],fa[1000010];
stack<long long> s;
void dfs(long long x)
{
    long long tmp=0;
    if(c[x]==')')
    {
        if(!s.empty())
        {
            tmp=s.top();
            s.pop();
            lst[x]=lst[fa[tmp]]+1;
        }
    }
    else
    {
        s.push(x);
    }
    sum[x]=sum[fa[x]]+lst[x];
    for(long long i:mp[x])
    {
        dfs(i);
    }
    if(tmp!=0)
    {
        s.push(tmp);
    }
    else
    {
        if(!s.empty())
        {
            s.pop();
        }
    }
}
int main()
{
    scanf("%lld%s",&n,c+1);
    for(long long i=2;i<=n;i++)
    {
        long long f;
        scanf("%lld",&f);
        mp[f].push_back(i);
        fa[i]=f;
    }
    dfs(1);
    long long ans=0;
    for(long long i=1;i<=n;i++)
    {
        ans^=(1ll*sum[i]*i);
    }
    printf("%lld",ans);
    return 0;
}
